mapper.select:
select w.id, w.title, m.nickname as artist_name, w.category, case when exists ( select 1 from tbl_auction a where a.work_id = w.id ) then '경매' else '거래' end as sale_type, w.status, to_char(w.created_datetime, 'YY.MM.DD') as created_datetime, w.view_count, ( select count(*) from tbl_report r where r.target_type = 'WORK' and r.target_id = w.id ) as report_count from tbl_work w join tbl_member m on w.member_id = m.id
w.deleted_datetime is null
and ( w.title ilike '%' || #{keyword} || '%' or m.nickname ilike '%' || #{keyword} || '%' )
and w.status = #{status}
order by w.id desc limit #{size} offset #{offset}
